// // This is a 16-bit 2-to-1 multiplexer that selects between two 16-bit data inputs based on a single select line.
module mux_2to1 (
    input [7:0] data0,
    input [7:0] data1,
    input sel,
    output reg [7:0] out
);
    always @(*) begin
        if (sel) 
            out = data1;
        else 
            out = data0;
    end
endmodule
